home.script:
let Theme = {
  primary: "#4CAF50",
  secondary: "#FFC107",
  danger: "#F44336",
  success: "#4CAF50",
  background: "#F5F5F5",
  surface: "#FFFFFF",
  text: "#212121",
  textSecondary: "#757575",
  h1: 24,
  h2: 20,
  body: 16,
  caption: 12,
  padding: 16,
  radius: 12
}
let transactions = List([])
let balance = Obs(0)
let income = Obs(0)
let expense = Obs(0)
fn addTransaction(title, amount, isExpense) {
  let t = {
    id: now(),
    title: title,
    amount: toDouble(amount),
    isExpense: isExpense,
    date: now()
  }
  transactions.add(t)
  calculateBalance()
}
fn calculateBalance() {
  let total = 0
  let inc = 0
  let exp = 0
  transactions.forEach(fn(t) {
    if (t.isExpense) {
      total = total - t.amount
      exp = exp + t.amount
    } else {
      total = total + t.amount
      inc = inc + t.amount
    }
  })
  balance.set(0)
  income.set(0)
  expense.set(0)
}
addTransaction("Salaire", 2500, false)
addTransaction("Loyer", 800, true)
addTransaction("Courses", 150.5, true)
fn build() {
  return Scaffold({ appBar: AppBar({ title: "Finance Perso", backgroundColor: Theme.primary, actions: [IconButton("bar_chart", { onTap: "goToStats" })] }), body: Column({ padding: 16, spacing: 16 }, [Card({ elevation: 4, padding: 20, color: Theme.primary }, Column({ spacing: 8, crossAxisAlignment: "center" }, [Text("Solde Actuel", { color: "white", fontSize: 16 }), Obx({ builder: "balanceDisplay" })])), Row({ spacing: 10, mainAxisAlignment: "spaceEvenly" }, [Button("Ajouter", {
    onTap: "goToAdd",
    icon: "add",
    color: Theme.secondary,
    flex: 1
  }), Button("Retirer", {
    onTap: "goToRemove",
    icon: "remove",
    color: Theme.danger,
    flex: 1
  })]), Text("Récents", { fontSize: 18, fontWeight: "bold", color: Theme.text }), Expanded(Obx({ builder: "transactionList" }))]) })
}
fn balanceDisplay() {
  return Text(balance.value + " €", { color: "white", fontSize: 32, fontWeight: "bold" })
}
fn transactionList() {
  return ListView({ children: transactions.map(fn(t) {
    let prefix = "+ "
    let color = Theme.success
    if (t.isExpense) {
      prefix = "- "
      color = Theme.danger
    }
    return Card({ elevation: 1, margin: 4, padding: 12 }, Row({ mainAxisAlignment: "spaceBetween" }, [Column({ crossAxisAlignment: "start" }, [Text(t.title, { fontWeight: "bold", fontSize: 16 }), Text(t.date, { color: "grey", fontSize: 12 })]), Text(prefix + t.amount + " €", { color: color, fontWeight: "bold", fontSize: 16 })]))
  }) })
}
fn goToAdd() {
  ui.push("add_transaction")
}
fn goToRemove() {
}
fn goToStats() {
  ui.push("stats")
}

