addTransaction("Salaire", 2500, false)
addTransaction("Loyer", 800, true)
addTransaction("Courses", 150.5, true)
let title = Obs("")
let amount = Obs("")
let isExpense = Obs(true)
fn build() {
  return Scaffold({ appBar: AppBar({ title: "Nouvelle Transaction", backgroundColor: Theme.primary }), body: Column({ padding: 16, spacing: 20 }, [Obx({ builder: "typeSelector" }), TextField({ label: "Titre", hint: "Ex: Courses, Loyer...", onChanged: "setTitle" }), TextField({ label: "Montant (€)", keyboardType: "number", onChanged: "setAmount" }), Button("Enregistrer", {
    onTap: "saveTransaction",
    fullWidth: true,
    size: "large",
    color: Theme.primary,
    icon: "check"
  })]) })
}
fn typeSelector() {
  let expenseColor = "grey"
  if (isExpense.value) {
    expenseColor = Theme.danger
  }
  let incomeColor = "grey"
  if (!isExpense.value) {
    incomeColor = Theme.success
  }
  return Row({ spacing: 10 }, [Button("Dépense", { color: expenseColor, onTap: "setExpense", flex: 1 }), Button("Revenu", { color: incomeColor, onTap: "setIncome", flex: 1 })])
}
fn setExpense() {
  isExpense.set(true)
}
fn setIncome() {
  isExpense.set(false)
}
fn setTitle(val) {
  title.set(val)
}
fn setAmount(val) {
  amount.set(val)
}
fn saveTransaction() {
  if (title.value == "" || amount.value == "") {
    return
  }
  addTransaction(title.value, amount.value, isExpense.value)
  ui.pop()
}

